213	            return {
214	              ...imageMetaData,
215	              ...removeOnlyUndefined({
216	                contentType,
217	                fileName,
218	                fileData,
219	                fileSize,
220	                nsfw,
221	              }),
222	            };
223	          }),
224	          ...responseMetaData,
225	        },
226	      },
227	    };
