---

### 3. **packages/openai/src/index.ts**
Main export file pattern:

```typescript
export { createOpenAI, openai } from './openai-provider';
export type { OpenAIProvider, OpenAIProviderSettings } from './openai-provider';
export type {
  OpenAIImageModelId,
  // ... other type exports
} from './image/openai-image-options';
export { VERSION } from './version';
```

For an image-only provider, you would export:
- Factory function: `createPixelArt`
- Default instance: `pixelart`
- Provider interface: `PixelArtProvider`
- Settings interface: `PixelArtProviderSettings`

---

### 4. **packages/openai/src/openai-provider.ts**
This is the core provider factory pattern. Here's the essential structure:

```typescript
import {
  ImageModelV3,
  ProviderV3,
} from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  loadOptionalSetting,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';

// Provider interface definition
export interface PixelArtProvider extends ProviderV3 {
  /**
   * Creates a model for image generation.
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Creates a model for image generation.
   */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

// Settings for the provider
export interface PixelArtProviderSettings {
  /**
   * Base URL for the PixelArt API calls.
   */
  baseURL?: string;

  /**
   * API key for authenticating requests.
   */
  apiKey?: string;

  /**
   * Custom headers to include in the requests.
   */
  headers?: Record<string, string>;

  /**
   * Provider name. Defaults to 'pixelart'.
   */
  name?: string;

  /**
   * Custom fetch implementation.
   */
  fetch?: FetchFunction;
}

/**
 * Create a PixelArt provider instance.
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(
      loadOptionalSetting({
        settingValue: options.baseURL,
        environmentVariableName: 'PIXELART_BASE_URL',
      }),
    ) ?? 'https://api.pixelart.com/v1';

  const providerName = options.name ?? 'pixelart';

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: `${providerName}.image`,
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const provider = function (modelId: PixelArtImageModelId) {
    return createImageModel(modelId);
  };

  provider.specificationVersion = 'v3' as const;
  provider.image = createImageModel;
  provider.imageModel = createImageModel;

  return provider as PixelArtProvider;
}

/**
 * Default PixelArt provider instance.
 */
export const pixelart = createPixelArt();
```

**Key Pattern Points:**
- Provider implements `ProviderV3` interface
- Uses `createXxx` factory function pattern
- Exports both function and default instance
- Uses utility functions: `loadApiKey`, `loadOptionalSetting`, `withoutTrailingSlash`, `withUserAgentSuffix`
- Each model factory returns a model instance configured with provider-specific settings
- Provider object itself is callable (returns default model)
- Has `specificationVersion: 'v3'` property

---

### 5. **packages/openai/src/image/openai-image-model.ts**
The ImageModel implementation - critical for your provider:

```typescript
import {
  ImageModelV3,
  ImageModelV3File,
  SharedV3Warning,
} from '@ai-sdk/provider';
import {
  combineHeaders,
  convertBase64ToUint8Array,
  convertToFormData,
  createJsonResponseHandler,
  downloadBlob,
  postFormDataToApi,
  postJsonToApi,
} from '@ai-sdk/provider-utils';
import { OpenAIConfig } from '../openai-config';
import { openaiFailedResponseHandler } from '../openai-error';

interface OpenAIImageModelConfig extends OpenAIConfig {
  _internal?: {
    currentDate?: () => Date;
  };
}

export class OpenAIImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get maxImagesPerCall(): number {
    return modelMaxImagesPerCall[this.modelId] ?? 1;
  }

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: OpenAIImageModelId,
    private readonly config: OpenAIImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    files,
    mask,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    // Handle unsupported features
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'This model does not support aspect ratio. Use `size` instead.',
      });
    }

    if (seed != null) {
      warnings.push({ type: 'unsupported', feature: 'seed' });
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    // Handle image editing (with files)
    if (files != null) {
      const { value: response, responseHeaders } = await postFormDataToApi({
        url: this.config.url({
          path: '/images/edits',
          modelId: this.modelId,
        }),
        headers: combineHeaders(this.config.headers(), headers),
        formData: convertToFormData<OpenAIImageEditInput>({
          model: this.modelId,
          prompt,
          image: await Promise.all(
            files.map(file =>
              file.type === 'file'
                ? new Blob(
                    [
                      file.data instanceof Uint8Array
                        ? new Blob([file.data as BlobPart], {
                            type: file.mediaType,
                          })
                        : new Blob([convertBase64ToUint8Array(file.data)], {
                            type: file.mediaType,
                          }),
                    ],
                    { type: file.mediaType },
                  )
                : downloadBlob(file.url),
            ),
          ),
          mask: mask != null ? await fileToBlob(mask) : undefined,
          n,
          size,
          ...(providerOptions.openai ?? {}),
        }),
        failedResponseHandler: openaiFailedResponseHandler,
        successfulResponseHandler: createJsonResponseHandler(
          openaiImageResponseSchema,
        ),
        abortSignal,
        fetch: this.config.fetch,
      });

      return {
        images: response.data.map(item => item.b64_json),
        warnings,
        usage: response.usage != null ? { ... } : undefined,
        response: {
          timestamp: currentDate,
          modelId: this.modelId,
          headers: responseHeaders,
        },
        providerMetadata: { ... },
      };
    }

    // Handle image generation (without files)
    const { value: response, responseHeaders } = await postJsonToApi({
      url: this.config.url({
        path: '/images/generations',
        modelId: this.modelId,
      }),
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        size,
        ...(providerOptions.openai ?? {}),
      },
      failedResponseHandler: openaiFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        openaiImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      usage: response.usage != null ? { ... } : undefined,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: { ... },
    };
  }
}

async function fileToBlob(
  file: ImageModelV3File | undefined,
): Promise<Blob | undefined> {
  if (!file) return undefined;

  if (file.type === 'url') {
    return downloadBlob(file.url);
  }

  const data =
    file.data instanceof Uint8Array
      ? file.data
      : convertBase64ToUint8Array(file.data);

  return new Blob([data as BlobPart], { type: file.mediaType });
}
```

**Key Pattern Points:**
- Implements `ImageModelV3` interface with `specificationVersion = 'v3'`
- Has readonly properties: `modelId`, `provider`
- Has `maxImagesPerCall` getter (can be number/undefined/function)
- `doGenerate()` is the core method
- Returns object with: `images`, `warnings`, `usage`, `response`, `providerMetadata`
- Uses utility functions: `combineHeaders`, `postJsonToApi`, `postFormDataToApi`, `createJsonResponseHandler`
- Handles image editing (with files) and generation (without files) separately
- Collects warnings for unsupported features

---

### 6. **packages/openai/src/image/openai-image-options.ts**
Model ID and configuration:

```typescript
export type OpenAIImageModelId =
  | 'dall-e-3'
  | 'dall-e-2'
  | 'gpt-image-1'
  | 'gpt-image-1-mini'
  | 'gpt-image-1.5'
  | 'chatgpt-image-latest'
  | (string & {});

export const modelMaxImagesPerCall: Record<OpenAIImageModelId, number> = {
  'dall-e-3': 1,
  'dall-e-2': 10,
  'gpt-image-1': 10,
  'gpt-image-1-mini': 10,
  'gpt-image-1.5': 10,
  'chatgpt-image-latest': 10,
};

const defaultResponseFormatPrefixes = [
  'chatgpt-image-',
  'gpt-image-1-mini',
  'gpt-image-1.5',
  'gpt-image-1',
];

export function hasDefaultResponseFormat(modelId: string): boolean {
  return defaultResponseFormatPrefixes.some(prefix =>
    modelId.startsWith(prefix),
  );
}
```

