### 4. **packages/openai/src/openai-provider.ts**
This is the core provider factory pattern. Here's the essential structure:

```typescript
import {
  ImageModelV3,
  ProviderV3,
} from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  loadOptionalSetting,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';

// Provider interface definition
export interface PixelArtProvider extends ProviderV3 {
  /**
   * Creates a model for image generation.
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Creates a model for image generation.
   */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

// Settings for the provider
export interface PixelArtProviderSettings {
  /**
   * Base URL for the PixelArt API calls.
   */
  baseURL?: string;

  /**
   * API key for authenticating requests.
   */
  apiKey?: string;

  /**
   * Custom headers to include in the requests.
   */
  headers?: Record<string, string>;

  /**
   * Provider name. Defaults to 'pixelart'.
   */
  name?: string;

  /**
   * Custom fetch implementation.
   */
  fetch?: FetchFunction;
}

/**
 * Create a PixelArt provider instance.
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(
      loadOptionalSetting({
        settingValue: options.baseURL,
        environmentVariableName: 'PIXELART_BASE_URL',
      }),
    ) ?? 'https://api.pixelart.com/v1';

  const providerName = options.name ?? 'pixelart';

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: `${providerName}.image`,
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const provider = function (modelId: PixelArtImageModelId) {
    return createImageModel(modelId);
  };

  provider.specificationVersion = 'v3' as const;
  provider.image = createImageModel;
  provider.imageModel = createImageModel;

  return provider as PixelArtProvider;
}

/**
 * Default PixelArt provider instance.
 */
export const pixelart = createPixelArt();
```

**Key Pattern Points:**
- Provider implements `ProviderV3` interface
- Uses `createXxx` factory function pattern
- Exports both function and default instance
- Uses utility functions: `loadApiKey`, `loadOptionalSetting`, `withoutTrailingSlash`, `withUserAgentSuffix`
- Each model factory returns a model instance configured with provider-specific settings
- Provider object itself is callable (returns default model)
- Has `specificationVersion: 'v3'` property

