     * The pixel art style to use for generation.
     */
    style?: 'pixel' | 'retro' | '8bit';
    /**
     * The pixel density of the generated image.
     * Higher values produce more detailed pixel art.
     */
    pixelDensity?: number;
}

interface PixelArtProvider extends ProviderV3 {
    (modelId: PixelArtImageModelId): ImageModelV3;
